import os
import django

# Настройка окружения Django
os.environ.setdefault('DJANGO_SETTINGS_MODULE', 'fishing_project.settings')
django.setup()

from shop.models import Product

def set_my_custom_images():
    
    my_images = {
        # === Воблеры и приманки ===
        'Megabass Great Hunting': 'data:image/jpeg;base64,',
        'Megabass Hazedong': 'data:image/webp;base64,',
        'Megabass Pop X': 'data:image/webp;base64,',
        'Megabass Vision 110': 'data:image/webp;base64,',
        'Rapala Husky Jerk': 'data:image/webp;base64,',
        'Rapala Mambo': 'data:image/webp;base64,',
        'Rapala Minnow Spoon': 'data:image/webp;base64,',
        'Rapala Shadow Rap': 'data:image/webp;base64,',
        'Rapala X-Rap': 'data:image/webp;base64,',
        'Savage Gear Craw': 'data:image/webp;base64,',
        'Savage Gear Pulse': 'data:image/webp;base64,',
        'Savage Gear Roach': 'data:image/webp;base64,',
        
        # === Катушки ===
        'Daiwa Fuego': 'data:image/webp;base64,',
        'Daiwa Legalis': 'data:image/webp;base64,',
        'Daiwa Tatula': 'data:image/webp;base64,',
        'Shimano Sedona': 'data:image/webp;base64,',
        'Shimano Stella': 'data:image/webp;base64,',
        
        # === Лески ===
        'Daiwa J-Braid': 'data:image/webp;base64,',
        'Rapala RAPLINE': 'data:image/webp;base64,',
        'Shimano Powerpro': 'data:image/webp;base64,',
        
        # === Снасти / Грузила / Крючки ===
        'Daiwa Bullet': 'data:image/webp;base64,',
        'Megabass Spec R': 'data:image/webp;base64,',
        'Rapala Ultra Point': 'data:image/webp;base64,',
        'Savage Gear Mega': 'data:image/webp;base64,',
        'Savage Gear Rig': 'data:image/webp;base64,',
        'Shimano Drop Shot': 'data:image/webp;base64,',
        
        # === Спиннинги ===
        'Daiwa Crossfire': 'data:image/webp;base64,',
        'Daiwa Prorex': 'data:image/webp;base64,',
        'Shimano Beast X': 'data:image/webp;base64,',
        'Shimano Soare': 'data:image/webp;base64,',
        'Shimano Ultegra': 'data:image/webp;base64,',
        
        # === Экипировка ===
        'Shimano Fishing Vest': 'data:image/webp;base64,',
    }

    products = Product.objects.all()
    count = 0
    
    for p in products:
        if p.name in my_images and my_images[p.name] != 'СЮДА_ССЫЛКУ':
            p.photo = my_images[p.name]
            p.save()
            print(f"Обновлено фото для: {p.name}")
            count += 1
            
    print(f"\n Готово! Успешно обновлено товаров: {count} из {products.count()}")

if __name__ == '__main__':
    set_my_custom_images()